// WriteBitmapBatch writes boolean values directly from a bitmap without converting to []bool.
// This avoids the 8x memory overhead and provides significant performance improvements.
// numValues specifies the number of boolean values to write from the bitmap.
func (w *BooleanColumnChunkWriter) WriteBitmapBatch(bitmap []byte, bitmapOffset int64, numValues int, defLevels, repLevels []int16) (valueOffset int64, err error) {
	defer func() {
		if r := recover(); r != nil {
			err = utils.FormatRecoveredError("unknown error type", r)
		}
	}()

	var n int64
	switch {
	case defLevels != nil:
		n = int64(len(defLevels))
	default:
		n = int64(numValues)
	}
	if err := w.validateVectorBatch(n); err != nil {
		return 0, err
	}

	w.doBatches(n, repLevels, func(offset, batch int64) {
		toWrite := w.writeLevels(batch, levelSliceOrNil(defLevels, offset, batch), levelSliceOrNil(repLevels, offset, batch))

		w.writeBitmapValues(bitmap, bitmapOffset+valueOffset, toWrite, batch-toWrite)
		if err := w.commitWriteAndCheckPageLimit(batch, toWrite); err != nil {
			panic(err)
		}

		valueOffset += toWrite
		w.checkDictionarySizeLimit()
	})
	return
}

