func (w *BooleanColumnChunkWriter) writeValues(values []bool, numNulls int64) {
	w.currentEncoder.(encoding.BooleanEncoder).Put(values)
	if w.pageStatistics != nil {
		w.pageStatistics.(*metadata.BooleanStatistics).Update(values, numNulls)
	}
	if w.bloomFilter != nil {
		// TODO: optimize for Dictionary Encoding case
		w.bloomFilter.InsertBulk(metadata.GetHashes(w.bloomFilter.Hasher(), values))
	}
}

func (w *BooleanColumnChunkWriter) writeValuesSpaced(spacedValues []bool, numRead, numValues int64, validBits []byte, validBitsOffset int64) {
	if len(spacedValues) != int(numRead) {
		w.currentEncoder.(encoding.BooleanEncoder).PutSpaced(spacedValues, validBits, validBitsOffset)
	} else {
		w.currentEncoder.(encoding.BooleanEncoder).Put(spacedValues)
	}
	if w.pageStatistics != nil {
		nulls := numValues - numRead
		w.pageStatistics.(*metadata.BooleanStatistics).UpdateSpaced(spacedValues, validBits, validBitsOffset, nulls)
	}
	if w.bloomFilter != nil {
		// TODO: optimize for Dictionary Encoding case
		w.bloomFilter.InsertBulk(metadata.GetSpacedHashes(w.bloomFilter.Hasher(), numRead, spacedValues, validBits, validBitsOffset))
	}
}

// writeBitmapValues writes boolean values directly from a bitmap
func (w *BooleanColumnChunkWriter) writeBitmapValues(bitmap []byte, bitmapOffset int64, numValues, numNulls int64) {
	// Check if encoder supports bitmap interface
	type bitmapEncoder interface {
		PutBitmap(bitmap []byte, offset int64, length int64)
	}

	if enc, ok := w.currentEncoder.(bitmapEncoder); ok {
		enc.PutBitmap(bitmap, bitmapOffset, numValues)
	} else {
		// Fallback: convert to []bool (slower but compatible)
		values := make([]bool, numValues)
		for i := int64(0); i < numValues; i++ {
			values[i] = bitutil.BitIsSet(bitmap, int(bitmapOffset+i))
		}
		w.currentEncoder.(encoding.BooleanEncoder).Put(values)
	}

	// Update statistics and bloom filter using bitmap-aware methods
	if w.pageStatistics != nil {
		w.pageStatistics.(*metadata.BooleanStatistics).UpdateFromBitmap(bitmap, bitmapOffset, numValues, numNulls)
	}
	if w.bloomFilter != nil {
		w.bloomFilter.InsertBulk(metadata.GetHashesFromBitmap(w.bloomFilter.Hasher(), bitmap, bitmapOffset, numValues))
	}
}

// writeBitmapValuesSpaced writes boolean values from a bitmap with validity information
func (w *BooleanColumnChunkWriter) writeBitmapValuesSpaced(bitmap []byte, bitmapOffset int64, numRead, numValues int64, validBits []byte, validBitsOffset int64) {
	// Try to use bitmap-aware encoder interface if available
	type bitmapSpacedEncoder interface {
		PutSpacedBitmap(bitmap []byte, bitmapOffset int64, numValues int64, validBits []byte, validBitsOffset int64) int64
	}

	if enc, ok := w.currentEncoder.(bitmapSpacedEncoder); ok {
		// Direct bitmap path - no []bool conversion!
		enc.PutSpacedBitmap(bitmap, bitmapOffset, numValues, validBits, validBitsOffset)
	} else {
		// Fallback: convert to []bool for encoders that don't support bitmap interface
		spacedValues := make([]bool, numValues)
		for i := int64(0); i < numValues; i++ {
			spacedValues[i] = bitutil.BitIsSet(bitmap, int(bitmapOffset+i))
		}

		if len(spacedValues) != int(numRead) {
			w.currentEncoder.(encoding.BooleanEncoder).PutSpaced(spacedValues, validBits, validBitsOffset)
		} else {
			w.currentEncoder.(encoding.BooleanEncoder).Put(spacedValues)
		}
	}

	// Use bitmap-aware statistics update
	if w.pageStatistics != nil {
		nulls := numValues - numRead
		w.pageStatistics.(*metadata.BooleanStatistics).UpdateFromBitmapSpaced(bitmap, bitmapOffset, numValues, validBits, validBitsOffset, nulls)
	}

	// Use bitmap-aware bloom filter hashing
	if w.bloomFilter != nil {
		w.bloomFilter.InsertBulk(metadata.GetSpacedHashesFromBitmap(w.bloomFilter.Hasher(), numRead, bitmap, bitmapOffset, numValues, validBits, validBitsOffset))
	}
}

func (w *BooleanColumnChunkWriter) checkDictionarySizeLimit() {
	if !w.hasDict || w.fallbackToNonDict {
		return
	}

	dictEnc := w.currentEncoder.(encoding.DictEncoder)
	if dictEnc.DictEncodedSize() >= int(w.props.DictionaryPageSizeLimit()) {
		w.FallbackToPlain()
		return
	}

	// Before any dict-encoded data page has been cut, check whether the
	// dictionary is actually saving space against a PLAIN baseline. Mirrors
	// parquet-mr's FallbackValuesWriter.shouldFallBack: if the dictionary
	// plus the encoded indices meet or exceed the raw input bytes, fall back
	// to PLAIN now and discard the dictionary — avoiding the mid-cardinality
	// case where a dict page stays in the file alongside PLAIN pages without
	// any net compression win.
	if !w.dictPageWritten && len(w.pages) == 0 {
		rawSize := dictEnc.ObservedRawSize()
		encodedSize := dictEnc.EstimatedDataEncodedSize()
		dictSize := int64(dictEnc.DictEncodedSize())
		// For an all-nulls batch rawSize, dictSize, and encodedSize are all 0,
		// so this 0 >= 0 path triggers. Harmless: nothing is encoded yet, so
		// PLAIN vs dict doesn't matter and we avoid an empty dictionary.
		if dictSize+encodedSize >= rawSize {
			w.FallbackToPlain()
		}
	}
}

// FallbackToPlain switches this column from dictionary to PLAIN encoding when
// the dictionary outgrows the configured page size limit. It mirrors
// parquet-mr's FallbackValuesWriter: unflushed buffered values are re-encoded
// as PLAIN (so the next data page is PLAIN, not dict-indexed), and the
// dictionary page is emitted only if a dict-encoded data page had already
// been cut before the overflow — otherwise the dictionary is discarded.
func (w *BooleanColumnChunkWriter) FallbackToPlain() {
	if w.currentEncoder.Encoding() != parquet.Encodings.PlainDict {
		return
	}

	dictEnc := w.currentEncoder.(encoding.DictEncoder)
	plainEnc := encoding.BooleanEncoderTraits.Encoder(format.Encoding(parquet.Encodings.Plain), false, w.descr, w.mem).(encoding.BooleanEncoder)

	if len(w.pages) > 0 {
		if err := w.WriteDictionaryPage(); err != nil {
			panic(err)
		}
		if err := w.drainBufferedDataPages(); err != nil {
			panic(err)
		}
	}

	if err := dictEnc.FallBackTo(plainEnc); err != nil {
		panic(err)
	}

	dictEnc.Release()
	w.currentEncoder = plainEnc
	w.encoding = parquet.Encodings.Plain
	w.fallbackToNonDict = true
}

// ByteArrayColumnChunkWriter is the typed interface for writing columns to a parquet
