// WriteBatch writes a batch of repetition levels, definition levels, and values to the
// column.
// `def_levels` (resp. `rep_levels`) can be null if the column's max definition level
// (resp. max repetition level) is 0.
// If not null, each of `def_levels` and `rep_levels` must have at least
// `len(values)`.
//
// The number of physical values written (taken from `values`) is returned.
// It can be smaller than `len(values)` is there are some undefined values.
//
// When using DataPageV2 to write a repeated column rows cannot cross data
// page boundaries. To ensure this the writer ensures that every batch of
// w.props.BatchSize begins and ends on a row boundary. As a consequence,
// the first value to WriteBatch must always be the beginning of a row if
// repLevels is not nil (repLevels[0] should always be 0) and using DataPageV2.
func (w *ByteArrayColumnChunkWriter) WriteBatch(values []parquet.ByteArray, defLevels, repLevels []int16) (valueOffset int64, err error) {
	defer func() {
		if r := recover(); r != nil {
			err = utils.FormatRecoveredError("unknown error type", r)
		}
	}()
	// We check for DataPage limits only after we have inserted the values. If a user
	// writes a large number of values, the DataPage size can be much above the limit.
	// The purpose of this chunking is to bound this. Even if a user writes large number
	// of values, the chunking will ensure the AddDataPage() is called at a reasonable
	// pagesize limit
	var n int64
	switch {
	case defLevels != nil:
		n = int64(len(defLevels))
	case values != nil:
		n = int64(len(values))
	}
	// VECTOR columns reject a partial-vector batch up front so callers get a typed
	// error (ErrVectorBatchMisaligned) rather than a recovered panic from deeper in
	// the write path. No-op for every other column.
	if err := w.validateVectorBatch(n); err != nil {
		return 0, err
	}
	// For variable-length types, we use adaptive batch sizing to ensure
	// each batch's encoded data stays well within int32 range. This prevents
	// overflow in FlushCurrentPage when computing uncompressed page size.
	const maxSafeBatchDataSize int64 = 1 << 30 // 1GB

	batchSize := w.props.WriteBatchSize()
	maxDefLevel := w.descr.MaxDefinitionLevel()
	isV2WithRep := w.props.DataPageVersion() != parquet.DataPageV1 &&
		repLevels != nil && w.descr.MaxRepetitionLevel() > 0
	// VECTOR columns (Option B) contribute a fixed number of leaf slots per row
	// and carry no per-element levels. Every batch must cover whole vectors so a
	// vector value is never split across data pages and rowsForLeafValues only
	// ever sees whole-vector counts. vectorLen is 0 for non-VECTOR columns, which
	// leaves the batching below unchanged.
	vectorLen := w.vectorLengthForBatch(n)
	batchSize = alignBatchToVector(batchSize, vectorLen)
	levelOffset := int64(0)

	for levelOffset < n {
		remaining := n - levelOffset
		batch := min(remaining, batchSize)

		// Scan values to find safe batch boundary
		if values != nil {
			valScan := valueOffset
			var cumDataSize int64
			for li := int64(0); li < batch; li++ {
				isValue := defLevels == nil || maxDefLevel == 0 ||
					defLevels[levelOffset+li] == maxDefLevel
				if isValue && valScan < int64(len(values)) {
					valSize := int64(len(values[valScan])) + 4
					if cumDataSize+valSize > maxSafeBatchDataSize && li > 0 {
						batch = li
						break
					}
					cumDataSize += valSize
					valScan++
				}
			}
		}

		// V2 row-boundary alignment
		if isV2WithRep && levelOffset+batch < n {
			for batch > 1 && repLevels[levelOffset+batch] != 0 {
				batch--
			}
		}
		// Keep every batch on a whole-vector boundary for VECTOR columns, even after
		// the data-size scan or V2 alignment trimmed it. A single vector that exceeds
		// the size cap is still written whole rather than split across pages.
		batch = alignBatchToVector(batch, vectorLen)
		if batch < 1 {
			batch = 1
		}

		// Process batch
		toWrite := w.writeLevels(batch, levelSliceOrNil(defLevels, levelOffset, batch),
			levelSliceOrNil(repLevels, levelOffset, batch))
		var vals []parquet.ByteArray
		if values != nil {
			vals = values[valueOffset : valueOffset+toWrite]
		}
		w.writeValues(vals, batch-toWrite)
		if err := w.commitWriteAndCheckPageLimit(batch, toWrite); err != nil {
			panic(err)
		}
		valueOffset += toWrite
		w.checkDictionarySizeLimit()
		levelOffset += batch
	}
	return
}

// WriteBatchSpaced writes a batch of repetition levels, definition levels, and values to the
