func (w *ByteArrayColumnChunkWriter) WriteDictIndices(indices arrow.Array, defLevels, repLevels []int16) (err error) {
	defer func() {
		if r := recover(); r != nil {
			err = utils.FormatRecoveredError("unknown error type", r)
		}
	}()

	valueOffset := int64(0)
	length := len(defLevels)
	if defLevels == nil {
		length = indices.Len()
	}
	if err := w.validateVectorBatch(int64(length)); err != nil {
		return err
	}

	dictEncoder := w.currentEncoder.(encoding.DictEncoder)

	w.doBatchesAlignedForVector(int64(length), repLevels, func(offset, batch int64) {
		info := w.maybeCalculateValidityBits(levelSliceOrNil(defLevels, offset, batch), batch)
		w.writeLevelsSpaced(batch, levelSliceOrNil(defLevels, offset, batch), levelSliceOrNil(repLevels, offset, batch))

		writeableIndices := array.NewSlice(indices, valueOffset, valueOffset+info.numSpaced())
		defer writeableIndices.Release()
		writeableIndices = w.maybeReplaceValidity(writeableIndices, info.nullCount)
		defer writeableIndices.Release()

		if err := dictEncoder.PutIndices(writeableIndices); err != nil {
			panic(err) // caught above
		}

		if err := w.commitWriteAndCheckPageLimit(batch, info.batchNum); err != nil {
			panic(err)
		}

		valueOffset += info.numSpaced()
	})

	return
}

func (w *ByteArrayColumnChunkWriter) writeValues(values []parquet.ByteArray, numNulls int64) {
	w.currentEncoder.(encoding.ByteArrayEncoder).Put(values)
	if w.pageStatistics != nil {
		w.pageStatistics.(*metadata.ByteArrayStatistics).Update(values, numNulls)
	}
	if w.bloomFilter != nil {
		// TODO: optimize for Dictionary Encoding case
		w.bloomFilter.InsertBulk(metadata.GetHashes(w.bloomFilter.Hasher(), values))
	}
}

func (w *ByteArrayColumnChunkWriter) writeValuesSpaced(spacedValues []parquet.ByteArray, numRead, numValues int64, validBits []byte, validBitsOffset int64) {
	if len(spacedValues) != int(numRead) {
		w.currentEncoder.(encoding.ByteArrayEncoder).PutSpaced(spacedValues, validBits, validBitsOffset)
	} else {
		w.currentEncoder.(encoding.ByteArrayEncoder).Put(spacedValues)
	}
	if w.pageStatistics != nil {
		nulls := numValues - numRead
		w.pageStatistics.(*metadata.ByteArrayStatistics).UpdateSpaced(spacedValues, validBits, validBitsOffset, nulls)
	}
	if w.bloomFilter != nil {
		// TODO: optimize for Dictionary Encoding case
		w.bloomFilter.InsertBulk(metadata.GetSpacedHashes(w.bloomFilter.Hasher(), numRead, spacedValues, validBits, validBitsOffset))
	}
}

func (w *ByteArrayColumnChunkWriter) checkDictionarySizeLimit() {
	if !w.hasDict || w.fallbackToNonDict {
		return
	}

	dictEnc := w.currentEncoder.(encoding.DictEncoder)
	if dictEnc.DictEncodedSize() >= int(w.props.DictionaryPageSizeLimit()) {
		w.FallbackToPlain()
		return
	}

	// Before any dict-encoded data page has been cut, check whether the
	// dictionary is actually saving space against a PLAIN baseline. Mirrors
	// parquet-mr's FallbackValuesWriter.shouldFallBack: if the dictionary
	// plus the encoded indices meet or exceed the raw input bytes, fall back
	// to PLAIN now and discard the dictionary — avoiding the mid-cardinality
	// case where a dict page stays in the file alongside PLAIN pages without
	// any net compression win.
	if !w.dictPageWritten && len(w.pages) == 0 {
		rawSize := dictEnc.ObservedRawSize()
		encodedSize := dictEnc.EstimatedDataEncodedSize()
		dictSize := int64(dictEnc.DictEncodedSize())
		// For an all-nulls batch rawSize, dictSize, and encodedSize are all 0,
		// so this 0 >= 0 path triggers. Harmless: nothing is encoded yet, so
		// PLAIN vs dict doesn't matter and we avoid an empty dictionary.
		if dictSize+encodedSize >= rawSize {
			w.FallbackToPlain()
		}
	}
}

// FallbackToPlain switches this column from dictionary to PLAIN encoding when
// the dictionary outgrows the configured page size limit. It mirrors
// parquet-mr's FallbackValuesWriter: unflushed buffered values are re-encoded
// as PLAIN (so the next data page is PLAIN, not dict-indexed), and the
// dictionary page is emitted only if a dict-encoded data page had already
// been cut before the overflow — otherwise the dictionary is discarded.
func (w *ByteArrayColumnChunkWriter) FallbackToPlain() {
	if w.currentEncoder.Encoding() != parquet.Encodings.PlainDict {
		return
	}

	dictEnc := w.currentEncoder.(encoding.DictEncoder)
	plainEnc := encoding.ByteArrayEncoderTraits.Encoder(format.Encoding(parquet.Encodings.Plain), false, w.descr, w.mem).(encoding.ByteArrayEncoder)

	if len(w.pages) > 0 {
		if err := w.WriteDictionaryPage(); err != nil {
			panic(err)
		}
		if err := w.drainBufferedDataPages(); err != nil {
			panic(err)
		}
	}

	if err := dictEnc.FallBackTo(plainEnc); err != nil {
		panic(err)
	}

	dictEnc.Release()
	w.currentEncoder = plainEnc
	w.encoding = parquet.Encodings.Plain
	w.fallbackToNonDict = true
}

